mapper.update:
UPDATE event.organizations
SET
     name = #{organizationName}
    ,org_type = #{orgType}
    ,contact_email = #{contactEmail}
    ,contact_phone = #{contactPhone}
    ,website = #{website}
    ,grade = COALESCE(NULLIF(#{grade,jdbcType=VARCHAR}, ''), grade)
    ,updated_by = #{updatedBy}
    ,updated_at = NOW()
WHERE organization_seq = #{organizationSeq}

UPDATE event.organizations
SET
     updated_by = #{approvedBy}
    ,updated_at = NOW()
WHERE organization_seq IN (
    SELECT organization_seq
    FROM event.organization_members
    WHERE user_seq = #{userSeq}
)
